module ring_counter_10bit (
    input clk,
    input reset,
    output reg [9:0] q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 10'b0000000001;
    else
        q <= {q[8:0], q[9]};
    end

endmodule
